import React from 'react';
import { Users, UserCheck, AlertTriangle } from 'lucide-react';
import { motion } from 'framer-motion';

const Panel = ({ icon: Icon, label, value, trend, colorClass }) => (
  <motion.div 
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    className="mas-panel p-6 flex flex-col justify-between group hover:border-mas-red/30 transition-all border-l-4"
    style={{ borderLeftColor: value === '0' && label.includes('Alerts') ? '#1C1C1E' : '#C8102E' }}
  >
    <div className="flex justify-between items-start">
      <div>
        <p className="text-[10px] uppercase tracking-[0.2em] text-mas-text-dim font-bold mb-1">{label}</p>
        <h3 className="text-3xl font-bold text-white tracking-tight">{value}</h3>
      </div>
      <div className={`p-3 bg-mas-gray border border-mas-border group-hover:border-mas-red/50 transition-all`}>
        <Icon className="text-mas-red" size={24} strokeWidth={1.5} />
      </div>
    </div>

    <div className="mt-4 flex items-center gap-2">
      <div className={`text-[10px] font-bold uppercase tracking-widest ${trend.includes('+') ? 'text-green-500' : 'text-mas-text-dim'}`}>
        {trend}
      </div>
      <p className="text-[10px] text-mas-text-dim uppercase tracking-widest">Since last hour</p>
    </div>
  </motion.div>
);

const OverviewPanels = () => {
  const stats = [
    { label: 'Total Visits Today', value: '1,284', icon: Users, trend: '+12%', colorClass: 'mas-red' },
    { label: 'Active Visitors', value: '42', icon: UserCheck, trend: 'Stable', colorClass: 'mas-red' },
    { label: 'Alerts & Violations', value: '03', icon: AlertTriangle, trend: '+2', colorClass: 'mas-red' },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
      {stats.map((stat, index) => (
        <Panel key={index} {...stat} />
      ))}
    </div>
  );
};

export default OverviewPanels;
